package main

import (
    "database/sql"
    "fmt"
    "log"

    _ "github.com/mattn/go-sqlite3"
)

type Player struct {
    ID     int
    Name   string
    Health int
    Attack int
    Level  int
}

func main() {
    db, err := sql.Open("sqlite3", "./transactions.db")
    if err != nil {
        log.Fatal(err)
    }
    defer db.Close()

    // ---- Create table ----
    db.Exec(`CREATE TABLE IF NOT EXISTS players (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        name TEXT,
        health INTEGER,
        attack INTEGER,
        level INTEGER
    )`)

    // ---- Prepared statements ----
    fmt.Println("=== Prepared Statements ===\n")

    // Prepare insert statement
    insertStmt, err := db.Prepare("INSERT INTO players (name, health, attack, level) VALUES (?, ?, ?, ?)")
    if err != nil {
        log.Fatal(err)
    }
    defer insertStmt.Close()

    // Execute multiple times
    players := []struct {
        Name   string
        Health int
        Attack int
        Level  int
    }{
        {"Hero", 100, 20, 5},
        {"Aragorn", 120, 25, 8},
        {"Gandalf", 80, 15, 6},
    }

    for _, p := range players {
        res, err := insertStmt.Exec(p.Name, p.Health, p.Attack, p.Level)
        if err != nil {
            log.Fatal(err)
        }
        id, _ := res.LastInsertId()
        fmt.Printf("Inserted %s with ID %d\n", p.Name, id)
    }

    // Prepare select statement
    selectStmt, err := db.Prepare("SELECT id, name, health, attack, level FROM players WHERE id = ?")
    if err != nil {
        log.Fatal(err)
    }
    defer selectStmt.Close()

    // ---- Transactions ----
    fmt.Println("\n=== Transactions ===\n")

    // Start transaction
    tx, err := db.Begin()
    if err != nil {
        log.Fatal(err)
    }

    // Multiple operations in transaction
    _, err = tx.Exec("INSERT INTO players (name, health, attack, level) VALUES (?, ?, ?, ?)",
        "Legolas", 90, 22, 7)
    if err != nil {
        tx.Rollback()
        log.Fatal(err)
    }

    _, err = tx.Exec("UPDATE players SET health = health + 10 WHERE name = ?", "Hero")
    if err != nil {
        tx.Rollback()
        log.Fatal(err)
    }

    // Commit transaction
    err = tx.Commit()
    if err != nil {
        log.Fatal(err)
    }
    fmt.Println("Transaction committed")

    // ---- Prepared statement with transaction ----
    fmt.Println("\n=== Prepared Statement with Transaction ===\n")

    tx2, err := db.Begin()
    if err != nil {
        log.Fatal(err)
    }
    defer tx2.Rollback()

    stmt, err := tx2.Prepare("INSERT INTO players (name, health, attack, level) VALUES (?, ?, ?, ?)")
    if err != nil {
        log.Fatal(err)
    }
    defer stmt.Close()

    _, err = stmt.Exec("Gimli", 110, 23, 6)
    if err != nil {
        log.Fatal(err)
    }

    err = tx2.Commit()
    if err != nil {
        log.Fatal(err)
    }
    fmt.Println("Prepared transaction committed")

    // ---- Query results ----
    fmt.Println("\n=== All Players ===\n")
    rows, err := db.Query("SELECT id, name, health, attack, level FROM players ORDER BY id")
    if err != nil {
        log.Fatal(err)
    }
    defer rows.Close()

    for rows.Next() {
        var p Player
        rows.Scan(&p.ID, &p.Name, &p.Health, &p.Attack, &p.Level)
        fmt.Printf("%d: %s (HP: %d, ATK: %d, Lv: %d)\n",
            p.ID, p.Name, p.Health, p.Attack, p.Level)
    }

    // ---- Rollback example ----
    fmt.Println("\n=== Rollback Example ===\n")

    tx3, err := db.Begin()
    if err != nil {
        log.Fatal(err)
    }

    _, err = tx3.Exec("INSERT INTO players (name, health, attack, level) VALUES (?, ?, ?, ?)",
        "Temporary", 50, 10, 1)
    if err != nil {
        tx3.Rollback()
        log.Fatal(err)
    }

    // Simulate error
    err = fmt.Errorf("something went wrong")
    if err != nil {
        tx3.Rollback()
        fmt.Println("Transaction rolled back due to error")
    }

    // Verify rollback
    var count int
    db.QueryRow("SELECT COUNT(*) FROM players WHERE name = ?", "Temporary").Scan(&count)
    fmt.Printf("Temporary player count after rollback: %d\n", count)
}

