package main

import (
    "database/sql"
    "fmt"
    "log"

    _ "github.com/mattn/go-sqlite3"
)

type Product struct {
    ID    int
    Name  string
    Price float64
}

func main() {
    db, err := sql.Open("sqlite3", "./products.db")
    if err != nil {
        log.Fatal(err)
    }
    defer db.Close()

    // Create table
    db.Exec(`CREATE TABLE IF NOT EXISTS products (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        name TEXT,
        price REAL
    )`)

    // ---- Prepared statement ----
    insertStmt, err := db.Prepare("INSERT INTO products (name, price) VALUES (?, ?)")
    if err != nil {
        log.Fatal(err)
    }
    defer insertStmt.Close()

    // Insert 3 products
    items := []struct {
        Name  string
        Price float64
    }{
        {"Sword", 50.0},
        {"Shield", 40.0},
        {"Potion", 10.0},
    }

    fmt.Println("=== Inserting products ===")
    for _, item := range items {
        res, err := insertStmt.Exec(item.Name, item.Price)
        if err != nil {
            log.Fatal(err)
        }
        id, _ := res.LastInsertId()
        fmt.Printf("Inserted: %s (ID: %d)\n", item.Name, id)
    }

    // ---- Transaction ----
    fmt.Println("\n=== Transaction ===")
    tx, err := db.Begin()
    if err != nil {
        log.Fatal(err)
    }

    // Insert new product
    _, err = tx.Exec("INSERT INTO products (name, price) VALUES (?, ?)", "Bow", 60.0)
    if err != nil {
        tx.Rollback()
        log.Fatal(err)
    }

    // Update existing product
    _, err = tx.Exec("UPDATE products SET price = price + 5 WHERE name = ?", "Sword")
    if err != nil {
        tx.Rollback()
        log.Fatal(err)
    }

    err = tx.Commit()
    if err != nil {
        log.Fatal(err)
    }
    fmt.Println("Transaction committed")

    // ---- Query results ----
    fmt.Println("\n=== All products ===")
    rows, err := db.Query("SELECT id, name, price FROM products ORDER BY id")
    if err != nil {
        log.Fatal(err)
    }
    defer rows.Close()

    for rows.Next() {
        var p Product
        rows.Scan(&p.ID, &p.Name, &p.Price)
        fmt.Printf("%d: %s ($%.2f)\n", p.ID, p.Name, p.Price)
    }
}
